const MEDRXIV_API_BASE = 'https://api.biorxiv.org/details/medrxiv';

export const fetchMedRxivArticles = async (
  topic: Topic | string,
  language: 'es' | 'original' = 'original',
  customQuery?: string
): Promise<ResearchUpdate> => {
  try {
    // MedRxiv API is strictly date-interval based, it does not support keyword search via API directly.
    // We fetch the latest batch and filter client-side.
    const endDate = new Date().toISOString().split('T')[0];
    const startDateObj = new Date();
    startDateObj.setMonth(startDateObj.getMonth() - 2); // Last 2 months to keep it relevant and performant
    const startDate = startDateObj.toISOString().split('T')[0];

    // Request format: server/interval/cursor/format
    const url = `${MEDRXIV_API_BASE}/${startDate}/${endDate}/0/json`;

    const response = await fetch(url);
    if (!response.ok) throw new Error(`MedRxiv API Error: ${response.status}`);

    const data = await response.json();
    const papers = data.collection || [];

    if (papers.length === 0) return { summary: "No recent preprints found.", articles: [] };

    // Client-side filtering because MedRxiv API doesn't support query params
    const filterTerm = customQuery ? customQuery.toLowerCase() : (typeof topic === 'string' ? topic.toLowerCase() : 'nephrology');
    const keywords = filterTerm.split(' ').filter((w: string) => w.length > 3);

    const relevantPapers = papers.filter((p: any) => {
        const text = (p.title + " " + p.abstract + " " + p.category).toLowerCase();
        // Always include Nephrology category
        if (p.category?.toLowerCase() === 'nephrology') return true;
        // Or check keywords
        return keywords.some((k: string) => text.includes(k));
    });

    const articles: Article[] = relevantPapers.slice(0, 30).map((item: any) => {
      const title = item.title || 'Untitled';
      const abstract = item.abstract || "No abstract available.";
      const source = `MedRxiv (${item.category || 'Preprint'})`;
      const date = item.date || 'N/A';
      const year = new Date(date).getFullYear();

      const relevance = calculateBaseClinicalScore(title, abstract, source, typeof topic === 'string' ? topic : '', 0, year);

      return {
        id: `mx-${item.doi}`,
        title: `[PREPRINT] ${title}`,
        summary: abstract,
        source: source,
        authors: item.authors || '',
        url: `https://www.medrxiv.org/content/${item.doi}v1`,
        date: date,
        category: 'Preprint',
        relevanceScore: relevance - 5, // Slight penalty as it is not peer-reviewed
        topic: typeof topic === 'string' ? topic : 'General',
        isFree: true 
      };
    });

    return {
      summary: `MedRxiv: ${articles.length} preprints found.`,
      articles: articles
    };

  } catch (error) {
    console.debug("MedRxiv Service Info:", error);
    return { summary: "Error fetching MedRxiv", articles: [] };
  }
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ResearchUpdate, Article } from "../types";

const getAIClient = (apiKey?: string) => {
  const key = apiKey || process.env.API_KEY;
  return new GoogleGenAI({ apiKey: key || "" });
};

const sanitizeUrl = (url: string): string => {
  if (!url || typeof url !== 'string') return '';
  const clean = url.trim();
  if (!clean || ['n/a', 'not available', 'no link', 'pending'].includes(clean.toLowerCase())) {
    return '';
  }
  if (/^https?:\/\//i.test(clean)) {
    return clean;
  }
  return `https://${clean}`;
};

const cleanJson = (text: string): string => {
  if (!text) return "{}";
  let clean = text.trim();
  if (clean.startsWith('```json')) {
      clean = clean.replace(/^```json/, '').replace(/```$/, '');
  } else if (clean.startsWith('```')) {
      clean = clean.replace(/^```/, '').replace(/```$/, '');
  }
  return clean.trim();
};

/**
 * Searches specifically for Latin American & Caribbean literature (LILACS, SciELO).
 */
export const fetchLilacsArticles = async (
    query: string,
    language: 'es' | 'original' = 'es',
    apiKey?: string
): Promise<ResearchUpdate> => {
    try {
        const ai = getAIClient(apiKey);

        const prompt = `
        Search specifically for medical articles indexed in LILACS (Latin American and Caribbean Health Sciences Literature), SciELO, and BVS regarding: "${query}".
        Focus on results from Latin American journals (e.g., Brazil, Mexico, Argentina, Colombia).
        Current year is 2026. Prioritize 2024-2026.

        Return JSON object with 'articles' array.
        Format: { "articles": [{ "title": "...", "summary": "...", "source": "SciELO/LILACS Journal Name", "url": "...", "date": "YYYY-MM-DD", "category": "Research", "relevanceScore": 85 }] }
        `;

        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                responseMimeType: "application/json"
            }
        });

        const result = JSON.parse(cleanJson(response.text || '{}')) as ResearchUpdate;
        if (result.articles) {
            result.articles = result.articles.map((a, i) => ({
                ...a,
                id: `lilacs-${Date.now()}-${i}`,
                source: a.source || "LILACS/SciELO",
                isFree: true, // SciELO is mostly OA
                url: sanitizeUrl(a.url)
            }));
        }
        return result || { summary: "", articles: [] };

    } catch (e) {
        console.error("LILACS Search Error", e);
        return { summary: "LILACS unavailable", articles: [] };
    }
};

